evals.prompt:
This screen targets Kotlin 2.1 with Strong Skipping on by default. Make `RowItem` skip recomposition when unrelated screen state changes:
@Composable fun Rows(items: List<Row>, onOpen: (Row) -> Unit) {
    LazyColumn { itemsIndexed(items) { i, row ->
        RowItem(row, isFirst = i == 0, onClick = { onOpen(row) })
    } }
}
